target_user = "Charlie"
channel_prefix = "External"

channels = get_channels()

exact_matches = [channel for channel in channels if channel.startswith(channel_prefix)]
case_insensitive_matches = [channel for channel in channels if channel.lower().startswith(channel_prefix.lower())]

if len(exact_matches) == 1:
    target_channel = exact_matches[0]
elif len(exact_matches) > 1:
    raise ValueError("Multiple channels found starting with {}".format(channel_prefix))
elif len(case_insensitive_matches) == 1:
    target_channel = case_insensitive_matches[0]
elif len(case_insensitive_matches) == 0:
    raise ValueError("No channel found starting with {}".format(channel_prefix))
else:
    raise ValueError("Multiple channels found starting with {}".format(channel_prefix))

channel_users = get_users_in_channel(target_channel)

if target_user in channel_users:
    print("{} is already in {}".format(target_user, target_channel))
else:
    add_user_to_channel(target_user, target_channel)
    print("Added {} to {}".format(target_user, target_channel))
